import React, { useState } from 'react';

const AddMaterial = ({ handleAdd }) => {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [unitOfMeasure, setUnitOfMeasure] = useState('');
  const [pricePerUnit, setPricePerUnit] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    
    const newMaterial = {
      name,
      description,
      unit_of_measure: unitOfMeasure,
      price_per_unit: parseFloat(pricePerUnit),
    };
    
    handleAdd(newMaterial);
    setName('');
    setDescription('');
    setUnitOfMeasure('');
    setPricePerUnit('');
  };

  return (
    <div>
      <h2>Add Material</h2>
      <form onSubmit={handleSubmit}>
        <label>
          Name:
          <input type="text" value={name} onChange={(e) => setName(e.target.value)} required />
        </label>
        <label>
          Description:
          <input type="text" value={description} onChange={(e) => setDescription(e.target.value)} required />
        </label>
        <label>
          Unit of Measure:
          <input type="text" value={unitOfMeasure} onChange={(e) => setUnitOfMeasure(e.target.value)} required />
        </label>
        <label>
          Price per Unit:
          <input type="number" value={pricePerUnit} onChange={(e) => setPricePerUnit(e.target.value)} required />
        </label>
        <button type="submit">Add</button>
      </form>
    </div>
  );
};

export default AddMaterial;
